import React, { useState } from 'react';
import Cookie from 'cookie-universal';
import { useNavigate } from 'react-router-dom';
import '../../Styles/Auth.css';

export default function Register() {
    const [form, setForm] = useState({
        name: '',
        email: '',
        password: '',
        password_confirmation: ''
    });
    const [loading, setLoading] = useState(false);
    const [err, setErr] = useState('');

    const cookie = Cookie();
    const navigate = useNavigate();

    function handleChange(e) {
        setForm({ ...form, [e.target.name]: e.target.value });
    }

    async function handleSubmit(e) {
        e.preventDefault();
        setLoading(true);
        setErr('');

        try {
            const response = await fetch('http://127.0.0.1:8000/api/register', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Accept': 'application/json'
                },
                body: JSON.stringify({
                    name: form.name,
                    email: form.email,
                    password: form.password,
                    password_confirmation: form.password_confirmation
                })
            });

            const data = await response.json();

            if (!response.ok) {
                if (response.status === 422) {
                    throw new Error('البريد الإلكتروني مستخدم مسبقاً');
                }
                throw new Error(data.message || 'فشل التسجيل');
            }

            console.log('Register Success:', data);

            const token = data.token;
            const user = data.user;

            cookie.set('educational-token', token);
            cookie.set('educational-user', JSON.stringify(user));

            setLoading(false);
            window.location.pathname = '/';

        } catch (error) {
            setLoading(false);
            console.error('Register Error:', error);
            setErr(error.message || 'حدث خطأ في التسجيل');
        }
    }

    return (
        <div className="auth-container">
            <div className="auth-box">
                <h2>إنشاء حساب جديد</h2>
                <p className="auth-subtitle">انضم إلى منصتنا التعليمية</p>

                {err && <div className="error-message">{err}</div>}

                <form onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label>الاسم الكامل</label>
                        <input
                            type="text"
                            name="name"
                            value={form.name}
                            onChange={handleChange}
                            placeholder="أدخل اسمك الكامل"
                            required
                        />
                    </div>

                    <div className="form-group">
                        <label>البريد الإلكتروني</label>
                        <input
                            type="email"
                            name="email"
                            value={form.email}
                            onChange={handleChange}
                            placeholder="example@email.com"
                            required
                        />
                    </div>

                    <div className="form-group">
                        <label>كلمة المرور</label>
                        <input
                            type="password"
                            name="password"
                            value={form.password}
                            onChange={handleChange}
                            placeholder="أدخل كلمة المرور"
                            required
                            minLength="8"
                        />
                    </div>

                    <div className="form-group">
                        <label>تأكيد كلمة المرور</label>
                        <input
                            type="password"
                            name="password_confirmation"
                            value={form.password_confirmation}
                            onChange={handleChange}
                            placeholder="أعد إدخال كلمة المرور"
                            required
                            minLength="8"
                        />
                    </div>

                    <button type="submit" className="auth-btn" disabled={loading}>
                        {loading ? 'جاري التسجيل...' : 'إنشاء حساب'}
                    </button>
                </form>

                <p className="auth-footer">
                    لديك حساب بالفعل؟ <a href="/login">تسجيل الدخول</a>
                </p>
            </div>
        </div>
    );
}
